{
  "name": "WhatsApp Message Router",
  "nodes": [
    {
      "parameters": {
        "updates": ["com.twilio.messaging.inbound-message.received"]
      },
      "id": "twilio-trigger-001",
      "name": "Twilio Trigger",
      "type": "n8n-nodes-base.twilioTrigger",
      "typeVersion": 1,
      "position": [480, 320],
      "webhookId": "{{USERDATA_PROCESS_INSTANCE_UID_ATADRESU}}-main-router",
      "credentials": {
        "twilioApi": {
          "id": "{{ORGCRED_TWILIO_ID_DERCGRO}}",
          "name": "{{ORGCRED_TWILIO_NAME_DERCGRO}}"
        }
      }
    },
    {
      "parameters": {
        "jsCode": "// Process input and parse phone numbers\nconst input = $input.item.json;\nconst data = input.data || input;\n\n// Parse prefixed phone numbers (whatsapp:+1234567890)\nconst rawFrom = data.from || '';\nconst rawTo = data.to || '';\n\nconst senderPhone = rawFrom.replace(/^(whatsapp|sms):/, '');\nconst twilioPhone = rawTo.replace(/^(whatsapp|sms):/, '');\nconst isWhatsApp = rawFrom.startsWith('whatsapp:');\n\n// Bot phone number from deployment parameter\nconst botPhone = {{INSTPARM_USER_BOT_PHONE_MRAPTSNI}};\n\n// Check if this message is for the bot\nconst isUserBot = twilioPhone === botPhone;\n\nconsole.log('=== Message Received ===');\nconsole.log('From:', senderPhone);\nconsole.log('To:', twilioPhone);\nconsole.log('Bot Phone:', botPhone);\nconsole.log('Is User Bot:', isUserBot);\n\nreturn [{\n  json: {\n    senderPhone,\n    twilioPhone,\n    isWhatsApp,\n    isUserBot,\n    messageBody: data.body || '',\n    messageSid: data.messageSid,\n    timestamp: data.timestamp || new Date().toISOString(),\n    _rawData: data\n  }\n}];"
      },
      "id": "process-input-001",
      "name": "Process Input",
      "type": "n8n-nodes-base.code",
      "typeVersion": 2,
      "position": [672, 320]
    },
    {
      "parameters": {
        "conditions": {
          "options": {
            "caseSensitive": true,
            "leftValue": "",
            "typeValidation": "strict"
          },
          "conditions": [
            {
              "id": "is-user-bot-check",
              "leftValue": "={{ $json.isUserBot }}",
              "rightValue": true,
              "operator": {
                "type": "boolean",
                "operation": "equals"
              }
            }
          ],
          "combinator": "and"
        },
        "options": {}
      },
      "id": "filter-user-bot-001",
      "name": "Is User Bot?",
      "type": "n8n-nodes-base.if",
      "typeVersion": 2.2,
      "position": [864, 320]
    },
    {
      "parameters": {
        "jsCode": "// Stop execution - not for this workflow\nconsole.log('Message not for user bot - stopping');\nreturn [];"
      },
      "id": "stop-not-user-bot-001",
      "name": "Stop (Not User Bot)",
      "type": "n8n-nodes-base.code",
      "typeVersion": 2,
      "position": [1056, 496]
    },
    {
      "parameters": {
        "resource": "initializeExecution",
        "operation": "initWorkflow",
        "memberSecret": "{{MEMSECRT_EXECUTION_AUTH_TRCESMEM}}",
        "organizationId": "{{USERDATA_ORGANIZATION_ID_ATADRESU}}",
        "userId": "{{USERDATA_USER_ID_ATADRESU}}",
        "processInstanceId": "{{USERDATA_PROCESS_INSTANCE_UID_ATADRESU}}",
        "workflowId": "main-router",
        "triggerType": "twilio"
      },
      "id": "codika-init-001",
      "name": "Codika Init",
      "type": "n8n-nodes-codika.codika",
      "typeVersion": 1,
      "position": [1056, 160]
    },
    {
      "parameters": {
        "operation": "getAll",
        "tableId": "users_with_startups",
        "returnAll": false,
        "limit": 1,
        "filterType": "string",
        "filterString": "={{ 'phone_number=eq.' + $('Process Input').first().json.senderPhone.replace('+', '') }}"
      },
      "id": "get-user-by-phone-001",
      "name": "Get User by Phone",
      "type": "n8n-nodes-base.supabase",
      "typeVersion": 1,
      "position": [1248, 160],
      "alwaysOutputData": true,
      "credentials": {
        "supabaseApi": {
          "id": "{{INSTCRED_SUPABASE_ID_DERCTSNI}}",
          "name": "{{INSTCRED_SUPABASE_NAME_DERCTSNI}}"
        }
      }
    },
    {
      "parameters": {
        "jsCode": "// Determine user type from database lookup\nconst userResult = $input.all();\nconst triggerData = $('Process Input').first().json;\nconst codikaInit = $('Codika Init').first().json;\n\n// Check if user exists\nconst existingUser = userResult.length > 0 && userResult[0].json.phone_number \n  ? userResult[0].json \n  : null;\n\n// Determine user_type (or 'not_found' if user doesn't exist)\nconst userType = existingUser?.user_type || 'not_found';\n\nconsole.log('=== User Lookup ===');\nconsole.log('Sender Phone:', triggerData.senderPhone);\nconsole.log('User Exists:', !!existingUser);\nconsole.log('User Type:', userType);\nif (existingUser) {\n  console.log('User Name:', existingUser.name);\n  console.log('Startup:', existingUser.startup_name);\n}\n\nreturn [{\n  json: {\n    ...triggerData,\n    _config: {\n      COMMUNITY_NAME: {{INSTPARM_COMMUNITY_NAME_MRAPTSNI}}\n    },\n    _user: {\n      exists: !!existingUser,\n      userData: existingUser,\n      userType: userType\n    }\n  }\n}];"
      },
      "id": "determine-user-type-001",
      "name": "Determine User Type",
      "type": "n8n-nodes-base.code",
      "typeVersion": 2,
      "position": [1440, 160]
    },
    {
      "parameters": {
        "mode": "rules",
        "rules": {
          "values": [
            {
              "outputKey": "admin",
              "conditions": {
                "options": {
                  "caseSensitive": true,
                  "leftValue": "",
                  "typeValidation": "strict"
                },
                "conditions": [
                  {
                    "id": "admin-check",
                    "leftValue": "={{ $json._user.userType }}",
                    "rightValue": "admin",
                    "operator": {
                      "type": "string",
                      "operation": "equals"
                    }
                  }
                ],
                "combinator": "and"
              }
            },
            {
              "outputKey": "resident",
              "conditions": {
                "options": {
                  "caseSensitive": true,
                  "leftValue": "",
                  "typeValidation": "strict"
                },
                "conditions": [
                  {
                    "id": "resident-check",
                    "leftValue": "={{ $json._user.userType }}",
                    "rightValue": "resident",
                    "operator": {
                      "type": "string",
                      "operation": "equals"
                    }
                  }
                ],
                "combinator": "and"
              }
            },
            {
              "outputKey": "community",
              "conditions": {
                "options": {
                  "caseSensitive": true,
                  "leftValue": "",
                  "typeValidation": "strict"
                },
                "conditions": [
                  {
                    "id": "community-check",
                    "leftValue": "={{ $json._user.userType }}",
                    "rightValue": "community",
                    "operator": {
                      "type": "string",
                      "operation": "equals"
                    }
                  }
                ],
                "combinator": "and"
              }
            },
            {
              "outputKey": "not_found",
              "conditions": {
                "options": {
                  "caseSensitive": true,
                  "leftValue": "",
                  "typeValidation": "strict"
                },
                "conditions": [
                  {
                    "id": "not-found-check",
                    "leftValue": "={{ $json._user.userType }}",
                    "rightValue": "not_found",
                    "operator": {
                      "type": "string",
                      "operation": "equals"
                    }
                  }
                ],
                "combinator": "and"
              }
            }
          ]
        },
        "options": {
          "fallbackOutput": "extra"
        }
      },
      "id": "route-by-user-type-001",
      "name": "Route by User Type",
      "type": "n8n-nodes-base.switch",
      "typeVersion": 3.2,
      "position": [1632, 160]
    },
    {
      "parameters": {
        "workflowId": {
          "__rl": true,
          "mode": "id",
          "value": "{{SUBWKFL_handler-admin_LFKWBUS}}"
        },
        "workflowInputs": {
          "mappingMode": "defineBelow",
          "value": {
            "senderPhone": "={{ $json.senderPhone }}",
            "twilioPhone": "={{ $json.twilioPhone }}",
            "messageBody": "={{ $json.messageBody }}",
            "userData": "={{ JSON.stringify($json._user.userData) }}",
            "executionId": "={{ $('Codika Init').first().json.executionId }}",
            "executionSecret": "={{ $('Codika Init').first().json.executionSecret }}",
            "communityName": "={{ $json._config.COMMUNITY_NAME }}"
          }
        },
        "options": {
          "waitForSubWorkflow": true
        }
      },
      "id": "call-admin-handler-001",
      "name": "Call Admin Handler",
      "type": "n8n-nodes-base.executeWorkflow",
      "typeVersion": 1.3,
      "position": [1872, -176]
    },
    {
      "parameters": {
        "workflowId": {
          "__rl": true,
          "mode": "id",
          "value": "{{SUBWKFL_handler-resident_LFKWBUS}}"
        },
        "workflowInputs": {
          "mappingMode": "defineBelow",
          "value": {
            "senderPhone": "={{ $json.senderPhone }}",
            "twilioPhone": "={{ $json.twilioPhone }}",
            "messageBody": "={{ $json.messageBody }}",
            "userData": "={{ JSON.stringify($json._user.userData) }}",
            "executionId": "={{ $('Codika Init').first().json.executionId }}",
            "executionSecret": "={{ $('Codika Init').first().json.executionSecret }}",
            "communityName": "={{ $json._config.COMMUNITY_NAME }}"
          }
        },
        "options": {
          "waitForSubWorkflow": true
        }
      },
      "id": "call-resident-handler-001",
      "name": "Call Resident Handler",
      "type": "n8n-nodes-base.executeWorkflow",
      "typeVersion": 1.3,
      "position": [1872, 0]
    },
    {
      "parameters": {
        "workflowId": {
          "__rl": true,
          "mode": "id",
          "value": "{{SUBWKFL_handler-community_LFKWBUS}}"
        },
        "workflowInputs": {
          "mappingMode": "defineBelow",
          "value": {
            "senderPhone": "={{ $json.senderPhone }}",
            "twilioPhone": "={{ $json.twilioPhone }}",
            "messageBody": "={{ $json.messageBody }}",
            "userData": "={{ JSON.stringify($json._user.userData) }}",
            "executionId": "={{ $('Codika Init').first().json.executionId }}",
            "executionSecret": "={{ $('Codika Init').first().json.executionSecret }}",
            "communityName": "={{ $json._config.COMMUNITY_NAME }}"
          }
        },
        "options": {
          "waitForSubWorkflow": true
        }
      },
      "id": "call-community-handler-001",
      "name": "Call Community Handler",
      "type": "n8n-nodes-base.executeWorkflow",
      "typeVersion": 1.3,
      "position": [1872, 176]
    },
    {
      "parameters": {
        "workflowId": {
          "__rl": true,
          "mode": "id",
          "value": "{{SUBWKFL_handler-not-found_LFKWBUS}}"
        },
        "workflowInputs": {
          "mappingMode": "defineBelow",
          "value": {
            "senderPhone": "={{ $json.senderPhone }}",
            "twilioPhone": "={{ $json.twilioPhone }}",
            "messageBody": "={{ $json.messageBody }}",
            "executionId": "={{ $('Codika Init').first().json.executionId }}",
            "executionSecret": "={{ $('Codika Init').first().json.executionSecret }}",
            "communityName": "={{ $json._config.COMMUNITY_NAME }}"
          }
        },
        "options": {
          "waitForSubWorkflow": true
        }
      },
      "id": "call-not-found-handler-001",
      "name": "Call Not Found Handler",
      "type": "n8n-nodes-base.executeWorkflow",
      "typeVersion": 1.3,
      "position": [1872, 352]
    },
    {
      "parameters": {},
      "id": "merge-results-001",
      "name": "Merge Results",
      "type": "n8n-nodes-base.merge",
      "typeVersion": 3,
      "position": [2112, 160]
    },
    {
      "parameters": {
        "jsCode": "// Prepare final result from sub-workflow output\nconst subResult = $input.item.json;\nconst userType = $('Determine User Type').first().json._user.userType;\n\nconsole.log('=== Sub-Workflow Result ===');\nconsole.log('User Type:', userType);\nconsole.log('Action:', subResult.actionPerformed);\n\nreturn [{\n  json: {\n    response_sent: subResult.responseSent || true,\n    action_performed: subResult.actionPerformed || 'unknown',\n    user_type: userType,\n    handler_result: subResult\n  }\n}];"
      },
      "id": "prepare-final-result-001",
      "name": "Prepare Final Result",
      "type": "n8n-nodes-base.code",
      "typeVersion": 2,
      "position": [2304, 160]
    },
    {
      "parameters": {
        "resource": "workflowOutputs",
        "operation": "submitResult",
        "resultData": "={{ $json }}"
      },
      "id": "codika-submit-001",
      "name": "Codika Submit Result",
      "type": "n8n-nodes-codika.codika",
      "typeVersion": 1,
      "position": [2496, 160]
    },
    {
      "parameters": {
        "content": "## WhatsApp Message Router\n\nSingle entry point for all WhatsApp messages.\n\n**Routing by User Type (from Database):**\n- admin → Admin Handler\n- resident → Resident Handler\n- community → Community Handler\n- not_found → Not Found Handler\n\n**Database:** `users_with_startups` view\n\n**Admin detection:** Database only (user_type='admin')",
        "height": 300,
        "width": 400
      },
      "id": "sticky-info-001",
      "name": "Workflow Info",
      "type": "n8n-nodes-base.stickyNote",
      "typeVersion": 1,
      "position": [64, 240]
    }
  ],
  "connections": {
    "Twilio Trigger": {
      "main": [
        [
          {
            "node": "Process Input",
            "type": "main",
            "index": 0
          }
        ]
      ]
    },
    "Process Input": {
      "main": [
        [
          {
            "node": "Is User Bot?",
            "type": "main",
            "index": 0
          }
        ]
      ]
    },
    "Is User Bot?": {
      "main": [
        [
          {
            "node": "Codika Init",
            "type": "main",
            "index": 0
          }
        ],
        [
          {
            "node": "Stop (Not User Bot)",
            "type": "main",
            "index": 0
          }
        ]
      ]
    },
    "Codika Init": {
      "main": [
        [
          {
            "node": "Get User by Phone",
            "type": "main",
            "index": 0
          }
        ]
      ]
    },
    "Get User by Phone": {
      "main": [
        [
          {
            "node": "Determine User Type",
            "type": "main",
            "index": 0
          }
        ]
      ]
    },
    "Determine User Type": {
      "main": [
        [
          {
            "node": "Route by User Type",
            "type": "main",
            "index": 0
          }
        ]
      ]
    },
    "Route by User Type": {
      "main": [
        [
          {
            "node": "Call Admin Handler",
            "type": "main",
            "index": 0
          }
        ],
        [
          {
            "node": "Call Resident Handler",
            "type": "main",
            "index": 0
          }
        ],
        [
          {
            "node": "Call Community Handler",
            "type": "main",
            "index": 0
          }
        ],
        [
          {
            "node": "Call Not Found Handler",
            "type": "main",
            "index": 0
          }
        ]
      ]
    },
    "Call Admin Handler": {
      "main": [
        [
          {
            "node": "Merge Results",
            "type": "main",
            "index": 0
          }
        ]
      ]
    },
    "Call Resident Handler": {
      "main": [
        [
          {
            "node": "Merge Results",
            "type": "main",
            "index": 0
          }
        ]
      ]
    },
    "Call Community Handler": {
      "main": [
        [
          {
            "node": "Merge Results",
            "type": "main",
            "index": 0
          }
        ]
      ]
    },
    "Call Not Found Handler": {
      "main": [
        [
          {
            "node": "Merge Results",
            "type": "main",
            "index": 0
          }
        ]
      ]
    },
    "Merge Results": {
      "main": [
        [
          {
            "node": "Prepare Final Result",
            "type": "main",
            "index": 0
          }
        ]
      ]
    },
    "Prepare Final Result": {
      "main": [
        [
          {
            "node": "Codika Submit Result",
            "type": "main",
            "index": 0
          }
        ]
      ]
    }
  },
  "settings": {
    "executionOrder": "v1",
    "errorWorkflow": "{{ORGSECRET_ERROR_WORKFLOW_ID_TERCESORG}}"
  }
}

