// Executes the pending message send after admin confirmation

const staticData = $getWorkflowStaticData('global');
const pending = staticData.pendingMessage;

// Check if there's a pending message
if (!pending) {
  return {
    status: 'no_pending',
    message: 'No pending message to send. Use send_message first to prepare a message.'
  };
}

// Check if message expired (1 minute timeout)
if (Date.now() - pending.timestamp > 60000) {
  delete staticData.pendingMessage;
  return {
    status: 'expired',
    message: 'The pending message has expired. Please prepare a new message using send_message.'
  };
}

// Get Twilio phone for sending
const twilioPhone = $('Parse Input').first().json.twilioPhone;

// Prepare message data for sending
const messagesToSend = pending.recipients.map(r => ({
  recipientPhone: r.phone,
  recipientName: r.name,
  recipientStartup: r.startup,
  message: pending.message,
  fromPhone: twilioPhone
}));

// Clear the pending message
delete staticData.pendingMessage;

// Store messages to send in static data for the loop to process
staticData.messagesToSend = messagesToSend;

return {
  status: 'sending',
  count: messagesToSend.length,
  recipients: messagesToSend.map(m => m.recipientName),
  message: `Sending message to ${messagesToSend.length} recipient(s): ${messagesToSend.map(m => m.recipientName).join(', ')}`
};"
