      "parameters": {
        "jsCode": "// Prepare WhatsApp response\nconst agentOutput = $input.item.json;\nconst msgData = $('Parse Input').first().json;\n\nlet responseText = agentOutput.output || agentOutput.text || 'I could not generate a response. Please try again.';\n\n// Sanitize Markdown to WhatsApp format\n// Convert **bold** to *bold* (WhatsApp uses single asterisks)\nresponseText = responseText.replace(/\\*\\*([^*]+)\\*\\*/g, '*$1*');\n// Remove markdown headers (# ## ###) - WhatsApp doesn't support them\nresponseText = responseText.replace(/^#{1,6}\\s+/gm, '');\n\nconsole.log('=== Preparing WhatsApp Response ===');\nconsole.log('Response length:', responseText.length);\n\nreturn [{\n  json: {\n    senderPhone: msgData.senderPhone,\n    twilioPhone: msgData.twilioPhone,\n    responseText: responseText,\n    messageBody: msgData.messageBody\n  }\n}];"
