   128→        "name": "send_message",
   129→        "description": "Prepare a targeted WhatsApp message to send to members. Input must be a JSON string with: target (name, startup, or user_type value), type ('person', 'startup', or 'user_type'), and message. For user_type, use values like 'resident', 'community', or 'admin'. IMPORTANT: If multiple people match a name, this will return a list for clarification. After getting the ready response, you MUST ask the admin to confirm before calling confirm_send.",
   130→        "jsCode": "// Send Targeted Message Tool
// Finds matching recipients and prepares message for confirmation

const userData = $('Format User Data').first().json._userData;
const allUsers = userData.users;

let input;
try {
  input = JSON.parse($json.query || '{}');
} catch (e) {
  return { status: 'error', message: 'Invalid input format. Expected JSON with target, type, and message fields.' };
}

const { target, type, message } = input;

if (!target || !type || !message) {
  return { status: 'error', message: 'Missing required fields. Need: target, type (person/startup/user_type), message' };
}

// Find matching recipients
let matches = [];
if (type === 'startup') {
  matches = allUsers.filter(u =>
    u.startup.toLowerCase().includes(target.toLowerCase())
  );
} else if (type === 'person') {
  matches = allUsers.filter(u =>
    u.name.toLowerCase().includes(target.toLowerCase())
  );
} else if (type === 'user_type') {
  matches = allUsers.filter(u =>
    u.userType.toLowerCase() === target.toLowerCase()
  );
} else {
  return { status: 'error', message: 'Type must be "person", "startup", or "user_type"' };
}

// No matches found
if (matches.length === 0) {
  if (type === 'user_type') {
    return {
      status: 'not_found',
      message: `No users found with user_type "${target}". Valid user types: resident, community, admin`
    };
  }
  return {
    status: 'not_found',
    message: `No ${type} found matching "${target}". Available ${type === 'startup' ? 'startups' : 'members'}: ${type === 'startup' ? userData.startupList.join(', ') : allUsers.map(u => u.name).join(', ')}`
  };
}

// Multiple person matches - need disambiguation
if (type === 'person' && matches.length > 1) {
  return {
    status: 'clarification_needed',
    matches: matches.map(m => `${m.name} from ${m.startup}`),
    message: `Found ${matches.length} people matching "${target}". Please specify which one:\n${matches.map((m, i) => `${i + 1}. ${m.name} from ${m.startup}`).join('\n')}`
  };
}

// Store pending message in workflow static data
const staticData = $getWorkflowStaticData('global');
staticData.pendingMessage = {
  recipients: matches,
  message: message,
  timestamp: Date.now(),
  targetType: type,
  targetName: target
};

return {
  status: 'ready',
  recipients: matches.map(m => `${m.name} (${m.startup || m.userType})`),
  count: matches.length,
  message: message,
  instruction: `Ready to send to ${matches.length} recipient(s). Ask the admin to confirm by saying "yes" or "confirm", then call confirm_send.`
};"
