        "jsCode": "// Parse input from parent workflow\nconst input = $input.item.json;\n\nlet userData = null;\ntry {\n  userData = JSON.parse(input.userData || '{}');\n} catch (e) {\n  userData = {};\n}\n\nconsole.log('=== Admin Handler Started ===');\nconsole.log('Sender:', input.senderPhone);\nconsole.log('Message:', input.messageBody);\nconsole.log('Admin Name:', userData.name);\n\nreturn [{\n  json: {\n    senderPhone: input.senderPhone,\n    twilioPhone: input.twilioPhone,\n    messageBody: input.messageBody,\n    userData: userData,\n    executionId: input.executionId,\n    executionSecret: input.executionSecret,\n    communityName: input.communityName || 'WAT',\n    callerRole: 'admin',\n    startTimeMs: Date.now()\n  }\n}];"
