    {
      "parameters": {
        "jsCode": "// Format user data for AI context (members only - events fetched on-demand via tools)\nconst allUsers = $input.all();\nconst msgData = $('Parse Input').first().json;\n\n// Build user database summary\nconst users = allUsers.map(item => item.json).filter(u => u.phone_number);\n\nconst usersSummary = users.map(u => ({\n  id: u.id,\n  name: u.name || 'Unknown',\n  startup: u.startup_name || 'No startup',\n  website: u.startup_website || '',\n  phone: u.phone_number,\n  userType: u.user_type || 'community',\n  registered: u.registered_at || 'Unknown',\n  lastActive: u.last_message_at || 'Never'\n}));\n\n// Calculate user statistics\nconst totalUsers = users.length;\nconst uniqueStartups = [...new Set(users.map(u => u.startup_name).filter(Boolean))];\nconst userTypeStats = {\n  resident: users.filter(u => u.user_type === 'resident').length,\n  community: users.filter(u => u.user_type === 'community').length,\n  admin: users.filter(u => u.user_type === 'admin').length\n};\n\n// Store users in workflow static data for tools\nconst staticData = $getWorkflowStaticData('global');\nstaticData.usersData = usersSummary;\n\nconsole.log('=== User Data Prepared ===');\nconsole.log('Total Users:', totalUsers);\nconsole.log('Unique Startups:', uniqueStartups.length);\n\nreturn [{\n  json: {\n    ...msgData,\n    _userData: {\n      users: usersSummary,\n      totalUsers: totalUsers,\n      totalStartups: uniqueStartups.length,\n      startupList: uniqueStartups,\n      userTypeStats: userTypeStats,\n      formattedData: JSON.stringify(usersSummary, null, 2)\n    }\n  }\n}];"
      },
      "id": "format-user-data-001",
