        "description": "Query the community member database. Use this to find information about registered members, startups, statistics, user types, and contact details. Returns all member data for you to analyze.",
        "jsCode": "// Query Members Tool\n// Returns all member data for the AI to analyze and answer questions\n\nconst userData = $('Format User Data').first().json._userData;\n\nreturn {\n  totalMembers: userData.totalUsers,\n  totalStartups: userData.totalStartups,\n  startupList: userData.startupList,\n  userTypeStats: userData.userTypeStats,\n  userTypes: ['resident', 'community', 'admin'],\n  members: userData.users\n};"
      },
      "id": "tool-query-001",
      "name": "Query Members Tool",
      "type": "@n8n/n8n-nodes-langchain.toolCode",
